#include<bits/stdc++.h>
using namespace std;

bool f(int n){
    for(int i=2;i*i<=n;i++) if(n%i==0) return false;
    return true;
}
int main(){
    int n;
    cin>>n;
    //if(n<5) cout<<"empty";
     for(int i=3;i<=n-2;i++) if(f(i)) if(f(i+2)) printf("%d %d\n",i,i+2);    
    return 0;
}
